def process_financial_transactions(accounts, transactions):
    """
    Process financial transactions and update account balances.

    Parameters:
        accounts (dict): Mapping of account_id -> current balance
        transactions (list): Each transaction is a dict with keys:
            - "account_id": account identifier
            - "type": "deposit" or "withdrawal"
            - "amount": positive numeric amount

    Returns:
        dict: Updated account balances

    Raises:
        ValueError: If transaction data is invalid or withdrawal exceeds balance
        KeyError: If account_id does not exist in accounts
    """
    updated_accounts = dict(accounts)

